('programmer','Programmer Profesional','Tech','Jadilah programmer handal yang menciptakan solusi teknologi inovatif. Dari kode pertama hingga aplikasi yang digunakan jutaan orang, perjalananmu adalah petualangan logika dan kreativitas.','💻','#3B82F6','["Menulis 1000 baris kode pertama","Menyelesaikan project pribadi","Punya project di GitHub","Diterima kerja di perusahaan tech","Membuat aplikasi yang dipakai publik","Promosi jadi Senior Developer","Ciptakan startup tech sukses"]'::jsonb,'["Belajar konsep baru 30 menit","Coding project pribadi","Code review","Baca dokumentasi","Push ke GitHub","Solve coding challenge","Istirahat mata + stretching"]'::jsonb,'[{"dimension": "Belajar & Riset", "items": ["Baca dokumentasi tech", "Tutorial framework baru", "Riset best practices"]},{"dimension": "Coding", "items": ["Kerjakan fitur baru", "Debug existing code", "Unit testing"]},{"dimension": "Project", "items": ["Commit progress harian", "Code review tim", "Update README/docs"]},{"dimension": "Kolaborasi", "items": ["Daily standup meeting", "Pair programming", "Diskusi arsitektur"]},{"dimension": "Skill Development", "items": ["Solve LeetCode/HackerRank", "Baca tech blog", "Eksperimen stack baru"]},{"dimension": "Kesehatan", "items": ["Stretching leher + bahu", "Istirahat mata 10 menit", "Jalan kaki 15 menit"]}]'::jsonb,'[{"question": "Bidang programming favorit?", "type": "single_select", "options": [{"label": "Web Development", "value": "web"}, {"label": "Mobile Apps", "value": "mobile"}, {"label": "Data Science", "value": "data-science"}, {"label": "Game Development", "value": "game"}]},{"question": "Level pengalaman coding?", "type": "single_select", "options": [{"label": "Pemula", "value": "pemula"}, {"label": "Intermediate", "value": "intermediate"}, {"label": "Advance", "value": "advance"}, {"label": "Expert", "value": "expert"}]},{"question": "Target utama karir programming?", "type": "single_select", "options": [{"label": "Kerja di FAANG", "value": "faang"}, {"label": "Startup founder", "value": "startup"}, {"label": "Freelance sukses", "value": "freelance"}, {"label": "Senior Engineer", "value": "senior"}]},{"question": "Bahasa pemrograman favorit?", "type": "single_select", "options": [{"label": "JavaScript/TS", "value": "javascript"}, {"label": "Python", "value": "python"}, {"label": "Go/Rust", "value": "go"}, {"label": "Java/Kotlin", "value": "java"}]}]'::jsonb,'[{"title": "Tech Lead", "description": "Memimpin tim developer dalam membangun produk teknologi.", "slug": "alternative-tech-lead"},{"title": "Software Architect", "description": "Merancang arsitektur sistem untuk aplikasi skala besar.", "slug": "alternative-software-architect"},{"title": "CTO Startup", "description": "Menjadi Chief Technology Officer dan membangun produk dari nol.", "slug": "alternative-cto-startup"}]'::jsonb),
('ui-ux-designer','UI/UX Designer Profesional','Tech','Jadilah UI/UX Designer yang menciptakan pengalaman digital yang intuitif dan memukau. Setiap klik, swipe, dan interaksi adalah karya seni yang manusiawi.','✨','#A855F7','["Membuat wireframe project pertama","Portfolio diterima di Dribbble","Mendapat klien desain pertama","Bekerja di perusahaan tech","Mendesain aplikasi yang rilis","Memenangkan penghargaan desain","Lead designer di product unicorn"]'::jsonb,'["Riset user persona","Buat wireframe kasar","Desain hi-fi di Figma","Usability testing","Iterasi berdasarkan feedback","Update portfolio Dribbble","Belajar tren UI terbaru"]'::jsonb,'[{"dimension": "Riset", "items": ["User research analysis", "Competitor audit", "Buat user persona"]},{"dimension": "Desain", "items": ["Wireframing lo-fi", "Desain hi-fi Figma", "Buat design system"]},{"dimension": "Prototyping", "items": ["Buat interactive prototype", "Micro interaction", "User flow mapping"]},{"dimension": "Testing", "items": ["Usability test session", "Analisis feedback user", "Iterasi desain"]},{"dimension": "Portfolio", "items": ["Upload ke Dribbble/Behance", "Update case study", "Buat website portfolio"]},{"dimension": "Skill Development", "items": ["Belajar tools baru", "Baca artikel UX", "Ikut design challenge"]}]'::jsonb,'[{"question": "Bidang UX favorit?", "type": "single_select", "options": [{"label": "Mobile App", "value": "mobile-app"}, {"label": "Website", "value": "website"}, {"label": "Dashboard/SaaS", "value": "dashboard"}, {"label": "Game UI", "value": "game-ui"}]},{"question": "Level pengalaman desain?", "type": "single_select", "options": [{"label": "Pemula", "value": "pemula"}, {"label": "Intermediate", "value": "intermediate"}, {"label": "Advance", "value": "advance"}, {"label": "Expert", "value": "expert"}]},{"question": "Target utama karir UI/UX?", "type": "single_select", "options": [{"label": "Product Designer", "value": "product-designer"}, {"label": "UX Researcher", "value": "ux-researcher"}, {"label": "Design Lead", "value": "design-lead"}, {"label": "Freelance", "value": "freelance"}]},{"question": "Tools desain andalan?", "type": "single_select", "options": [{"label": "Figma", "value": "figma"}, {"label": "Sketch", "value": "sketch"}, {"label": "Adobe XD", "value": "adobe-xd"}, {"label": "Framer", "value": "framer"}]}]'::jsonb,'[{"title": "Product Designer", "description": "Mengelola end-to-end desain produk digital.", "slug": "alternative-product-designer"},{"title": "UX Researcher", "description": "Mendalami perilaku user untuk menciptakan produk yang tepat.", "slug": "alternative-ux-researcher"},{"title": "Design System Lead", "description": "Membangun design system untuk perusahaan skala besar.", "slug": "alternative-design-system-lead"}]'::jsonb),
('game-developer','Game Developer Profesional','Tech','Jadilah pengembang game yang menciptakan dunia virtual dan petualangan seru. Dari konsep hingga rilis, setiap game adalah mahakarya interaktif.','🎮','#10B981','["Membuat game sederhana pertama","Rilis game di Play Store","Game mencapai 10.000 download","Diterima di studio game","Membuat game PC/console","Game masuk featured store","Memenangkan award game indie"]'::jsonb,'["Brainstorm konsep game","Coding gameplay mechanics","Buat asset game","Playtest build harian","Fix bug + polish","Riset tren game","Update progress devlog"]'::jsonb,'[{"dimension": "Desain Game", "items": ["Buat Game Design Document", "Desain level layout", "Balance gameplay mechanics"]},{"dimension": "Programming", "items": ["Coding core mechanics", "Implementasi AI", "Optimasi performance"]},{"dimension": "Art & Asset", "items": ["Buat sprite/model 3D", "Desain UI game", "Animasi karakter"]},{"dimension": "Testing", "items": ["Playtest internal", "Bug tracking + fixing", "QA testing session"]},{"dimension": "Publikasi", "items": ["Build + export game", "Siapkan store listing", "Marketing materials"]},{"dimension": "Komunitas", "items": ["Post devlog", "Interaksi dengan player", "Dapat feedback beta"]}]'::jsonb,'[{"question": "Platform game target?", "type": "single_select", "options": [{"label": "Mobile", "value": "mobile"}, {"label": "PC/Desktop", "value": "pc"}, {"label": "Console", "value": "console"}, {"label": "Web", "value": "web"}]},{"question": "Level pengalaman game dev?", "type": "single_select", "options": [{"label": "Pemula", "value": "pemula"}, {"label": "Intermediate", "value": "intermediate"}, {"label": "Advance", "value": "advance"}, {"label": "Professional", "value": "professional"}]},{"question": "Role favorit dalam game dev?", "type": "single_select", "options": [{"label": "Programmer", "value": "programmer"}, {"label": "Game Designer", "value": "game-designer"}, {"label": "Artist", "value": "artist"}, {"label": "Producer", "value": "producer"}]},{"question": "Genre game favorit?", "type": "single_select", "options": [{"label": "Action/RPG", "value": "action-rpg"}, {"label": "Puzzle/Casual", "value": "puzzle"}, {"label": "Strategy", "value": "strategy"}, {"label": "Simulation", "value": "simulation"}]}]'::jsonb,'[{"title": "Game Producer", "description": "Mengelola produksi game dari konsep hingga rilis.", "slug": "alternative-game-producer"},{"title": "Technical Artist", "description": "Menjembatani antara art dan programming dalam game development.", "slug": "alternative-technical-artist"},{"title": "Game Studio Founder", "description": "Mendirikan dan memimpin studio game independen.", "slug": "alternative-game-studio-founder"}]'::jsonb),
('data-scientist','Data Scientist Profesional','Tech','Jadilah data scientist yang mengubah data mentah menjadi wawasan berharga. Dengan analisis dan machine learning, kamu membantu perusahaan membuat keputusan berbasis data.','📊','#F59E0B','["Menyelesaikan kursus data science pertama","Project analisis data pertama","Punya portfolio di Kaggle","Diterima sebagai data analyst","Membuat ML model production","Promosi jadi data scientist","Memimpin tim data"]'::jsonb,'["Baca data terbaru","Data cleaning","Eksplorasi data visual","Buat model ML","Evaluasi performance model","Update portfolio Kaggle","Belajar algoritma baru"]'::jsonb,'[{"dimension": "Data Preparation", "items": ["Kumpulkan data dari source", "Data cleaning + preprocessing", "Feature engineering"]},{"dimension": "Analisis", "items": ["Exploratory data analysis", "Visualisasi insight", "Statistical testing"]},{"dimension": "Machine Learning", "items": ["Pilih algoritma", "Train model", "Hyperparameter tuning"]},{"dimension": "Evaluation", "items": ["Evaluasi model metrics", "A/B testing analysis", "Model validation"]},{"dimension": "Deployment", "items": ["Deploy model ke API", "Monitoring performance", "Model retraining"]},{"dimension": "Skill Development", "items": ["Baca paper ML terbaru", "Kaggle competition", "Belajar tools baru"]}]'::jsonb,'[{"question": "Bidang data science favorit?", "type": "single_select", "options": [{"label": "Machine Learning", "value": "ml"}, {"label": "Deep Learning", "value": "deep-learning"}, {"label": "Data Analytics", "value": "analytics"}, {"label": "NLP/CV", "value": "nlp-cv"}]},{"question": "Level pengalaman data?", "type": "single_select", "options": [{"label": "Pemula", "value": "pemula"}, {"label": "Intermediate", "value": "intermediate"}, {"label": "Advance", "value": "advance"}, {"label": "Expert", "value": "expert"}]},{"question": "Target utama karir data?", "type": "single_select", "options": [{"label": "Data Analyst", "value": "data-analyst"}, {"label": "Data Engineer", "value": "data-engineer"}, {"label": "ML Engineer", "value": "ml-engineer"}, {"label": "AI Researcher", "value": "ai-researcher"}]},{"question": "Tools favorit untuk data?", "type": "single_select", "options": [{"label": "Python", "value": "python"}, {"label": "R", "value": "r"}, {"label": "SQL", "value": "sql"}, {"label": "TensorFlow/PyTorch", "value": "tensorflow"}]}]'::jsonb,'[{"title": "AI Engineer", "description": "Membangun sistem AI untuk aplikasi produksi.", "slug": "alternative-ai-engineer"},{"title": "Data Engineer", "description": "Merancang pipeline data untuk perusahaan skala besar.", "slug": "alternative-data-engineer"},{"title": "Research Scientist", "description": "Melakukan riset cutting-edge di bidang AI.", "slug": "alternative-research-scientist"}]'::jsonb),
('ai-specialist','AI Specialist Profesional','Tech','Jadilah spesialis AI yang mendorong batasan teknologi kecerdasan buatan. Dari pengembangan model hingga implementasi solusi AI, kamu adalah arsitek masa depan.','🤖','#06B6D4','["Menyelesaikan kursus AI/ML pertama","Membuat model AI sederhana","Project AI untuk social impact","Publikasi paper di jurnal","Bekerja di perusahaan AI","Mengembangkan produk AI","Memimpin tim riset AI"]'::jsonb,'["Baca paper riset AI","Latih model deep learning","Evaluasi model","Data collection + labeling","Eksperimen arsitektur baru","Diskusi dengan tim riset","Dokumentasi eksperimen"]'::jsonb,'[{"dimension": "Riset", "items": ["Baca paper AI terbaru", "Review state-of-the-art", "Literature survey"]},{"dimension": "Pengembangan Model", "items": ["Data pipeline preparation", "Model architecture design", "Training + optimization"]},{"dimension": "Evaluasi", "items": ["Model benchmarking", "Error analysis", "Ablation studies"]},{"dimension": "Deployment", "items": ["Model serving API", "Edge deployment", "Monitoring + logging"]},{"dimension": "Kolaborasi", "items": ["Diskusi dengan tim riset", "Presentasi progress", "Code review ML"]},{"dimension": "Skill", "items": ["Implementasi paper baru", "Kaggle grandmaster", "Buat tutorial AI"]}]'::jsonb,'[{"question": "Bidang AI favorit?", "type": "single_select", "options": [{"label": "Computer Vision", "value": "cv"}, {"label": "NLP", "value": "nlp"}, {"label": "Reinforcement Learning", "value": "rl"}, {"label": "Generative AI", "value": "gen-ai"}]},{"question": "Level pengalaman AI?", "type": "single_select", "options": [{"label": "Pemula", "value": "pemula"}, {"label": "Intermediate", "value": "intermediate"}, {"label": "Advance", "value": "advance"}, {"label": "Expert", "value": "expert"}]},{"question": "Target utama karir AI?", "type": "single_select", "options": [{"label": "AI Researcher", "value": "ai-researcher"}, {"label": "ML Engineer", "value": "ml-engineer"}, {"label": "AI Product Manager", "value": "ai-pm"}, {"label": "AI Startup Founder", "value": "ai-founder"}]},{"question": "Framework AI favorit?", "type": "single_select", "options": [{"label": "PyTorch", "value": "pytorch"}, {"label": "TensorFlow", "value": "tensorflow"}, {"label": "JAX", "value": "jax"}, {"label": "Hugging Face", "value": "huggingface"}]}]'::jsonb,'[{"title": "AI Researcher", "description": "Mendobrak batasan AI dengan riset dan publikasi ilmiah.", "slug": "alternative-ai-researcher"},{"title": "MLOps Engineer", "description": "Mengelola infrastruktur dan deployment model machine learning.", "slug": "alternative-mlops-engineer"},{"title": "AI Ethics Consultant", "description": "Memastikan pengembangan AI yang etis dan bertanggung jawab.", "slug": "alternative-ai-ethics"}]'::jsonb)
